/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * <Replace with your name(s) and NetID(s).>
 */

#include <assert.h>
#include <stdint.h>

#include "csapp.h"

static void	client_error(int fd, const char *cause, int err_num, 
		    const char *short_msg, const char *long_msg);
static char    *create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static int	parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);

/* Thread-safe buffer for storing pending connections (prethreading) */
typedef struct {
	int *buf;           /* Buffer of socket descriptors */
	int n;              /* Maximum number of items in buf */
	int front;          /* Index of first item in buf */
	int rear;           /* Index of last item in buf */
	int count;          /* Number of items in buf */
	pthread_mutex_t mutex;           /* Protects accesses to buf */
	pthread_cond_t notempty;         /* Signaled when buf becomes nonempty */
	pthread_cond_t notfull;          /* Signaled when buf becomes not full */
} sbuf_t;

/* Global variables for logging and thread management */
FILE *logfile = NULL;
pthread_mutex_t log_mutex;
sbuf_t sbuf;  /* Global shared buffer */

/* Thread pool configuration */
#define SBUFSIZE 16
#define NTHREADS 4

/* Function prototypes */
static void sbuf_init(sbuf_t *sp, int n);
static void sbuf_deinit(sbuf_t *sp);
static void sbuf_insert(sbuf_t *sp, int item);
static int sbuf_remove(sbuf_t *sp);
static void *thread_routine(void *arg);
static void handle_request(int fd, const struct sockaddr_in *client_addr);
static void forward_request(rio_t *rio, int server_fd, const char *hostname,
			    const char *pathname);
static void forward_response(int server_fd, int client_fd, const struct sockaddr_in *client_addr,
			     const char *uri);

/*
 * Requires:
 *   argc == 2 with port number as argv[1]
 *
 * Effects:
 *   Initializes the proxy server, opens listening socket, creates thread pool,
 *   and enters the main connection acceptance loop.
 */
int
main(int argc, char **argv)
{

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	/* Open log file for writing */
	logfile = fopen("proxy.log", "a");
	if (logfile == NULL) {
		fprintf(stderr, "Error: Could not open proxy.log for writing\n");
		exit(1);
	}

	/* Ignore SIGPIPE to prevent crashes on broken pipes */
	Signal(SIGPIPE, SIG_IGN);

	/* Initialize logging mutex */
	pthread_mutex_init(&log_mutex, NULL);

	/* Open listening socket */
	int listenfd = open_listenfd(argv[1]);
	if (listenfd < 0) {
		fprintf(stderr, "Error: Could not open listening socket on port %s\n", argv[1]);
		exit(1);
	}

	/* Initialize shared buffer for connection queue */
	sbuf_init(&sbuf, SBUFSIZE);

	/* Create thread pool */
	pthread_t tid;
	for (int i = 0; i < NTHREADS; i++) {
		Pthread_create(&tid, NULL, thread_routine, (void *)(intptr_t)i);
	}

	/* Main loop: accept connections and add to buffer */
	struct sockaddr_in client_addr;
	socklen_t client_len;
	while (1) {
		client_len = sizeof(client_addr);
		int connfd = Accept(listenfd, (struct sockaddr *)&client_addr, &client_len);
		if (connfd > 0) {
			sbuf_insert(&sbuf, connfd);
		}
	}

	/* Return success. */
	return (0);
}

/*
 * Requires:
 *   The parameter sp must point to a valid sbuf_t structure.
 *
 * Effects:
 *   Initializes an empty, bounded, FIFO buffer with a maximum of n items.
 */
static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf = Malloc(n * sizeof(int));
	sp->n = n;
	sp->front = sp->rear = sp->count = 0;
	pthread_mutex_init(&sp->mutex, NULL);
	pthread_cond_init(&sp->notempty, NULL);
	pthread_cond_init(&sp->notfull, NULL);
}

/*
 * Requires:
 *   The parameter sp must point to a valid sbuf_t structure.
 *
 * Effects:
 *   Cleans up the shared buffer.
 */
__attribute__((unused))
static void
sbuf_deinit(sbuf_t *sp)
{
	Free(sp->buf);
	pthread_mutex_destroy(&sp->mutex);
	pthread_cond_destroy(&sp->notempty);
	pthread_cond_destroy(&sp->notfull);
}

/*
 * Requires:
 *   The parameter sp must point to a valid sbuf_t structure.
 *
 * Effects:
 *   Insert item onto the rear of the shared FIFO buffer.
 *   Block the calling thread and wait if the buffer is already full.
 */
static void
sbuf_insert(sbuf_t *sp, int item)
{
	pthread_mutex_lock(&sp->mutex);
	while (sp->count >= sp->n)
		pthread_cond_wait(&sp->notfull, &sp->mutex);
	sp->buf[(++sp->rear) % (sp->n)] = item;
	sp->count++;
	pthread_cond_signal(&sp->notempty);
	pthread_mutex_unlock(&sp->mutex);
}

/*
 * Requires:
 *   The parameter sp must point to a valid sbuf_t structure.
 *
 * Effects:
 *   Remove and return the first item from the front of the shared FIFO buffer.
 *   Block the calling thread and wait if the buffer is currently empty.
 */
static int
sbuf_remove(sbuf_t *sp)
{
	pthread_mutex_lock(&sp->mutex);
	while (sp->count <= 0)
		pthread_cond_wait(&sp->notempty, &sp->mutex);
	int item = sp->buf[(++sp->front) % (sp->n)];
	sp->count--;
	pthread_cond_signal(&sp->notfull);
	pthread_mutex_unlock(&sp->mutex);
	return item;
}

/*
 * Requires:
 *   The parameter arg is the thread index (used for debugging).
 *
 * Effects:
 *   Thread routine that repeatedly gets a connection descriptor from the
 *   shared buffer and processes the HTTP request.
 */
static void *
thread_routine(void *arg)
{
	int thread_id = (intptr_t)arg;
	(void)thread_id;  /* Suppress unused warning if we're not using it for debug output */

	Pthread_detach(Pthread_self());

	while (1) {
		int connfd = sbuf_remove(&sbuf);
		struct sockaddr_in client_addr;
		socklen_t client_len = sizeof(client_addr);

		/* Get the peer address for logging */
		if (getpeername(connfd, (struct sockaddr *)&client_addr, &client_len) < 0) {
			close(connfd);
			continue;
		}

		handle_request(connfd, &client_addr);
		Close(connfd);
	}

	return NULL;
}

/*
 * Requires:
 *   The parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Given a URI from an HTTP proxy GET request (i.e., a URL), extract the
 *   host name, port, and path name.  Create strings containing the host name,
 *   port, and path name, and return them through the parameters "hostnamep",
 *   "portp", "pathnamep", respectively.  (The caller must free the memory
 *   storing these strings.)  Return -1 if there are any problems and 0
 *   otherwise.
 */
static int
parse_uri(const char *uri, char **hostnamep, char **portp, char **pathnamep)
{
	const char *pathname_begin, *port_begin, *port_end;

	if (strncasecmp(uri, "http://", 7) != 0)
		return (-1);

	/* Extract the host name. */
	const char *host_begin = uri + 7;
	const char *host_end = strpbrk(host_begin, ":/ \r\n");
	if (host_end == NULL)
		host_end = host_begin + strlen(host_begin);
	int len = host_end - host_begin;
	char *hostname = Malloc(len + 1);
	strncpy(hostname, host_begin, len);
	hostname[len] = '\0';
	*hostnamep = hostname;

	/* Look for a port number.  If none is found, use port 80. */
	if (*host_end == ':') {
		port_begin = host_end + 1;
		port_end = strpbrk(port_begin, "/ \r\n");
		if (port_end == NULL)
			port_end = port_begin + strlen(port_begin);
		len = port_end - port_begin;
	} else {
		port_begin = "80";
		port_end = host_end;
		len = 2;
	}
	char *port = Malloc(len + 1);
	strncpy(port, port_begin, len);
	port[len] = '\0';
	*portp = port;

	/* Extract the path. */
	if (*port_end == '/') {
		pathname_begin = port_end;
		const char *pathname_end = strpbrk(pathname_begin, " \r\n");
		if (pathname_end == NULL)
			pathname_end = pathname_begin + strlen(pathname_begin);
		len = pathname_end - pathname_begin;
	} else {
		pathname_begin = "/";
		len = 1;
	}
	char *pathname = Malloc(len + 1);
	strncpy(pathname, pathname_begin, len);
	pathname[len] = '\0';
	*pathnamep = pathname;

	return (0);
}

/*
 * Requires:
 *   The parameter "sockaddr" must point to a valid sockaddr_in structure.  The
 *   parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Returns a string containing a properly formatted log entry.  This log
 *   entry is based upon the socket address of the requesting client
 *   ("sockaddr"), the URI from the request ("uri"), and the size in bytes of
 *   the response from the server ("size").
 */
static char *
create_log_entry(const struct sockaddr_in *sockaddr, const char *uri, int size)
{
	struct tm result;

	/*
	 * Create a large enough array of characters to store a log entry.
	 * Although the length of the URI can exceed MAXLINE, the combined
	 * lengths of the other fields and separators cannot.
	 */
	const size_t log_maxlen = MAXLINE + strlen(uri);
	char *const log_str = Malloc(log_maxlen + 1);

	/* Get a formatted time string. */
	time_t now = time(NULL);
	int log_strlen = strftime(log_str, MAXLINE, "%a %d %b %Y %H:%M:%S %Z: ",
	    localtime_r(&now, &result));

	/*
	 * Convert the IP address in network byte order to dotted decimal
	 * form.
	 */
	Inet_ntop(AF_INET, &sockaddr->sin_addr, &log_str[log_strlen],
	    INET_ADDRSTRLEN);
	log_strlen += strlen(&log_str[log_strlen]);

	/*
	 * Assert that the time and IP address fields occupy less than half of
	 * the space that is reserved for the non-URI fields.
	 */
	assert(log_strlen < MAXLINE / 2);

	/*
	 * Add the URI and response size onto the end of the log entry.
	 */
	snprintf(&log_str[log_strlen], log_maxlen - log_strlen, " %s %d", uri,
	    size);

	return (log_str);
}

/*
 * Requires:
 *   The parameter "fd" must be an open socket that is connected to the client.
 *   The parameters "cause", "short_msg", and "long_msg" must point to properly 
 *   NUL-terminated strings that describe the reason why the HTTP transaction
 *   failed.  The string "short_msg" may not exceed 32 characters in length,
 *   and the string "long_msg" may not exceed 80 characters in length.
 *
 * Effects:
 *   Constructs an HTML page describing the reason why the HTTP transaction
 *   failed, and writes an HTTP/1.0 response containing that page as the
 *   content.  The cause appearing in the HTML page is truncated if the
 *   string "cause" exceeds 2048 characters in length.
 */
static void
client_error(int fd, const char *cause, int err_num, const char *short_msg,
    const char *long_msg)
{
	char body[MAXBUF], headers[MAXBUF], truncated_cause[2049];

	assert(strlen(short_msg) <= 32);
	assert(strlen(long_msg) <= 80);
	/* Ensure that "body" is much larger than "truncated_cause". */
	assert(sizeof(truncated_cause) < MAXBUF / 2);

	/*
	 * Create a truncated "cause" string so that the response body will not
	 * exceed MAXBUF.
	 */
	strncpy(truncated_cause, cause, sizeof(truncated_cause) - 1);
	truncated_cause[sizeof(truncated_cause) - 1] = '\0';

	/* Build the HTTP response body. */
	snprintf(body, MAXBUF,
	    "<html><title>Proxy Error</title><body bgcolor=""ffffff"">\r\n"
	    "%d: %s\r\n"
	    "<p>%s: %s\r\n"
	    "<hr><em>The COMP 321 Web proxy</em>\r\n",
	    err_num, short_msg, long_msg, truncated_cause);

	/* Build the HTTP response headers. */
	snprintf(headers, MAXBUF,
	    "HTTP/1.0 %d %s\r\n"
	    "Content-type: text/html\r\n"
	    "Content-length: %d\r\n"
	    "\r\n",
	    err_num, short_msg, (int)strlen(body));

	/* Write the HTTP response. */
	if (rio_writen(fd, headers, strlen(headers)) != -1)
		rio_writen(fd, body, strlen(body));
}

/*
 * Requires:
 *   The parameter "fd" must be an open socket connected to the client.
 *   The parameter "client_addr" must point to a valid sockaddr_in structure.
 *
 * Effects:
 *   Reads an HTTP request from the client, parses it, forwards it to the
 *   appropriate server, reads the response, and forwards it back to the client.
 */
static void
handle_request(int fd, const struct sockaddr_in *client_addr)
{
	rio_t rio;
	char buf[MAXLINE], method[MAXLINE], uri[MAXLINE], version[MAXLINE];
	char *hostname = NULL, *port = NULL, *pathname = NULL;

	/* Read request line */
	rio_readinitb(&rio, fd);
	if (rio_readlineb(&rio, buf, MAXLINE) <= 0)
		return;

	/* Parse request line */
	if (sscanf(buf, "%s %s %s", method, uri, version) != 3) {
		client_error(fd, buf, 400, "Bad Request",
		    "Invalid request line");
		return;
	}

	/* Only support GET requests */
	if (strcasecmp(method, "GET") != 0) {
		client_error(fd, method, 501, "Not Implemented",
		    "Proxy does not implement this method");
		return;
	}

	/* Parse the URI */
	if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
		client_error(fd, uri, 400, "Bad Request",
		    "Invalid URI");
		if (hostname) Free(hostname);
		if (port) Free(port);
		if (pathname) Free(pathname);
		return;
	}

	/* Connect to the server */
	int serverfd = open_clientfd(hostname, port);
	if (serverfd < 0) {
		client_error(fd, hostname, 502, "Bad Gateway",
		    "Failed to connect to server");
		Free(hostname);
		Free(port);
		Free(pathname);
		return;
	}

	/* Forward the request to the server */
	forward_request(&rio, serverfd, hostname, pathname);

	/* Forward the response back to the client */
	forward_response(serverfd, fd, client_addr, uri);

	/* Cleanup */
	Close(serverfd);
	Free(hostname);
	Free(port);
	Free(pathname);
}

/*
 * Requires:
 *   rio must point to a rio_t initialized on the client socket
 *   server_fd must be a socket connected to the server
 *   hostname must point to the hostname for the Host header (used if client doesn't provide)
 *   pathname must point to the path portion of the URI
 *
 * Effects:
 *   Reads the HTTP request from the client (via rio) and forwards it to the server,
 *   with modifications:
 *   - Rewrite the first line to use just the path (not full URI)
 *   - Remove Connection, Keep-Alive, and Proxy-Connection headers
 *   - Ensure Host header is sent (from client or generate if missing)
 *   - Add Connection: close header
 */
static void
forward_request(rio_t *rio, int server_fd, const char *hostname,
    const char *pathname)
{
	char buf[MAXLINE];
	char request_line[MAXLINE];
	int has_host = 0;

	/* Send modified request line to server */
	snprintf(request_line, MAXLINE, "GET %s HTTP/1.0\r\n", pathname);
	if (rio_writen(server_fd, request_line, strlen(request_line)) < 0)
		return;

	/* Read and forward remaining headers, filtering out connection headers */
	while (rio_readlineb(rio, buf, MAXLINE) > 0) {
		/* Check for empty line (end of headers) */
		if (strcmp(buf, "\r\n") == 0)
			break;

		/* Skip connection-related headers */
		if (strncasecmp(buf, "Connection:", 11) == 0 ||
		    strncasecmp(buf, "Keep-Alive:", 11) == 0 ||
		    strncasecmp(buf, "Proxy-Connection:", 16) == 0)
			continue;

		/* Check if client provided Host header */
		if (strncasecmp(buf, "Host:", 5) == 0)
			has_host = 1;

		/* Forward other headers */
		if (rio_writen(server_fd, buf, strlen(buf)) < 0)
			return;
	}

	/* If client didn't provide Host header, add it ourselves */
	if (!has_host) {
		snprintf(request_line, MAXLINE, "Host: %s\r\n", hostname);
		if (rio_writen(server_fd, request_line, strlen(request_line)) < 0)
			return;
	}

	/* Send Connection: close header and empty line to end headers */
	if (rio_writen(server_fd, "Connection: close\r\n\r\n", 22) < 0)
		return;
}

/*
 * Requires:
 *   server_fd must be a socket connected to the server
 *   client_fd must be a socket connected to the client
 *   client_addr must point to a valid sockaddr_in structure
 *   uri must point to a valid URI string
 *
 * Effects:
 *   Reads the HTTP response from the server, forwards it to the client,
 *   and logs the request.
 */
static void
forward_response(int server_fd, int client_fd, const struct sockaddr_in *client_addr,
    const char *uri)
{
	rio_t rio;
	char buf[MAXLINE];
	int total_size = 0;

	rio_readinitb(&rio, server_fd);

	/* Read response line by line and forward to client */
	while (rio_readlineb(&rio, buf, MAXLINE) > 0) {
		if (rio_writen(client_fd, buf, strlen(buf)) < 0)
			break;
		total_size += strlen(buf);

		/* Check for end of headers */
		if (strcmp(buf, "\r\n") == 0)
			break;
	}

	/* Forward the response body */
	ssize_t n;
	while ((n = rio_readnb(&rio, buf, MAXLINE)) > 0) {
		if (rio_writen(client_fd, buf, n) < 0)
			break;
		total_size += n;
	}

	/* Log the request */
	char *log_entry = create_log_entry(client_addr, uri, total_size);
	pthread_mutex_lock(&log_mutex);
	fprintf(logfile, "%s\n", log_entry);
	fflush(logfile);
	pthread_mutex_unlock(&log_mutex);
	Free(log_entry);
}

// Prevent "unused function" and "unused variable" warnings.
static const void *dummy_ref[] = { client_error, create_log_entry, dummy_ref,
    parse_uri };

