+ *   Remove and return the first item from the front of the shared FIFO buffer.
+ *   Block the calling thread and wait if the buffer is currently empty.
+ */
+static int
+sbuf_remove(sbuf_t *sp)
+{
+	pthread_mutex_lock(&sp->mutex);
+	while (sp->count <= 0)
+		pthread_cond_wait(&sp->notempty, &sp->mutex);
+	int item = sp->buf[(++sp->front) % (sp->n)];
+	sp->count--;
+	pthread_cond_signal(&sp->notfull);
+	pthread_mutex_unlock(&sp->mutex);
+	return item;
+}
